import{_ as i,c as e,o as s,ah as h}from"./chunks/framework.Cnj7lwEt.js";const c=JSON.parse('{"title":"GitHub 使用ガイド","description":"","frontmatter":{},"headers":[],"relativePath":"ja/github-guide.md","filePath":"ja/github-guide.md"}'),l={name:"ja/github-guide.md"};function t(r,a,n,d,o,k){return s(),e("div",null,a[0]||(a[0]=[h(`<h1 id="github-使用ガイド" tabindex="-1">GitHub 使用ガイド <a class="header-anchor" href="#github-使用ガイド" aria-label="Permalink to “GitHub 使用ガイド”">​</a></h1><h2 id="_01-1-はじめに" tabindex="-1">01.1- はじめに <a class="header-anchor" href="#_01-1-はじめに" aria-label="Permalink to “01.1- はじめに”">​</a></h2><p>GitHub は世界最大のコードホスティングプラットフォームで、開発者に強力なバージョン管理、共同開発、プロジェクト管理機能を提供しています。</p><h2 id="_01-2-基本概念" tabindex="-1">01.2- 基本概念 <a class="header-anchor" href="#_01-2-基本概念" aria-label="Permalink to “01.2- 基本概念”">​</a></h2><h3 id="_01-21-リポジトリ" tabindex="-1">01.21- リポジトリ <a class="header-anchor" href="#_01-21-リポジトリ" aria-label="Permalink to “01.21- リポジトリ”">​</a></h3><p>リポジトリはプロジェクトの保存空間で、すべてのファイル、フォルダ、および各ファイルの修正履歴を含みます。</p><h3 id="_01-22-ブランチ" tabindex="-1">01.22- ブランチ <a class="header-anchor" href="#_01-22-ブランチ" aria-label="Permalink to “01.22- ブランチ”">​</a></h3><p>ブランチを使用すると、メインブランチに影響を与えることなく、新機能の開発や問題の修正ができます。</p><h3 id="_01-23-コミット" tabindex="-1">01.23- コミット <a class="header-anchor" href="#_01-23-コミット" aria-label="Permalink to “01.23- コミット”">​</a></h3><p>コミットはファイルに対する変更の記録で、各コミットには一意の ID が生成されます。</p><h3 id="_01-24-プルリクエスト" tabindex="-1">01.24- プルリクエスト <a class="header-anchor" href="#_01-24-プルリクエスト" aria-label="Permalink to “01.24- プルリクエスト”">​</a></h3><p>プルリクエストは、変更をメインブランチにマージするリクエストで、コードレビューや議論を容易にします。</p><h2 id="_01-3-クイックスタート" tabindex="-1">01.3- クイックスタート <a class="header-anchor" href="#_01-3-クイックスタート" aria-label="Permalink to “01.3- クイックスタート”">​</a></h2><h3 id="_01-31-アカウント作成" tabindex="-1">01.31- アカウント作成 <a class="header-anchor" href="#_01-31-アカウント作成" aria-label="Permalink to “01.31- アカウント作成”">​</a></h3><p><a href="https://github.com" target="_blank" rel="noreferrer">GitHub 公式サイト</a> にアクセスしてアカウントを登録してください。</p><h3 id="_01-32-リポジトリ作成" tabindex="-1">01.32- リポジトリ作成 <a class="header-anchor" href="#_01-32-リポジトリ作成" aria-label="Permalink to “01.32- リポジトリ作成”">​</a></h3><ol><li>右上の「+」ボタンをクリック</li><li>「New repository」を選択</li><li>リポジトリ名と説明を入力</li><li>公開または非公開を選択</li><li>「Create repository」をクリック</li></ol><h3 id="_01-33-リポジトリのクローン" tabindex="-1">01.33- リポジトリのクローン <a class="header-anchor" href="#_01-33-リポジトリのクローン" aria-label="Permalink to “01.33- リポジトリのクローン”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/username/repository.git</span></span></code></pre></div><h3 id="_01-34-ブランチ作成" tabindex="-1">01.34- ブランチ作成 <a class="header-anchor" href="#_01-34-ブランチ作成" aria-label="Permalink to “01.34- ブランチ作成”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div><h3 id="_01-35-変更のコミット" tabindex="-1">01.35- 変更のコミット <a class="header-anchor" href="#_01-35-変更のコミット" aria-label="Permalink to “01.35- 変更のコミット”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;新機能を追加&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div><h3 id="_01-36-プルリクエスト作成" tabindex="-1">01.36- プルリクエスト作成 <a class="header-anchor" href="#_01-36-プルリクエスト作成" aria-label="Permalink to “01.36- プルリクエスト作成”">​</a></h3><p>GitHub ウェブページでプルリクエストを作成し、レビューとマージを待ちます。</p><h2 id="_01-4-よく使う操作" tabindex="-1">01.4- よく使う操作 <a class="header-anchor" href="#_01-4-よく使う操作" aria-label="Permalink to “01.4- よく使う操作”">​</a></h2><h3 id="_01-41-フォーク" tabindex="-1">01.41- フォーク <a class="header-anchor" href="#_01-41-フォーク" aria-label="Permalink to “01.41- フォーク”">​</a></h3><p>フォークを使用すると、他の人のプロジェクトを自分のアカウントにコピーして修正できます。</p><h3 id="_01-42-スター" tabindex="-1">01.42- スター <a class="header-anchor" href="#_01-42-スター" aria-label="Permalink to “01.42- スター”">​</a></h3><p>スターはプロジェクトが気に入ったことを示し、後で簡単に見つけることができます。</p><h3 id="_01-43-ウォッチ" tabindex="-1">01.43- ウォッチ <a class="header-anchor" href="#_01-43-ウォッチ" aria-label="Permalink to “01.43- ウォッチ”">​</a></h3><p>ウォッチを使用すると、プロジェクトの更新通知を受け取ることができます。</p><h3 id="_01-44-イシュー" tabindex="-1">01.44- イシュー <a class="header-anchor" href="#_01-44-イシュー" aria-label="Permalink to “01.44- イシュー”">​</a></h3><p>イシューは問題の報告、機能のリクエスト、またはアイデアの議論に使用されます。</p><h2 id="_01-5-ベストプラクティス" tabindex="-1">01.5- ベストプラクティス <a class="header-anchor" href="#_01-5-ベストプラクティス" aria-label="Permalink to “01.5- ベストプラクティス”">​</a></h2><ol><li><strong>明確なコミットメッセージ</strong> - 各コミットの目的を他の人に伝える</li><li><strong>ブランチを使用</strong> - メインブランチで直接開発しない</li><li><strong>定期的に同期</strong> - ローカルリポジトリをリモートリポジトリと同期</li><li><strong>コードレビュー</strong> - プルリクエストを通じてコードレビューを実施</li><li><strong>ドキュメント整備</strong> - プロジェクトに README と必要なドキュメントを追加</li></ol><h2 id="_01-6-関連リソース" tabindex="-1">01.6- 関連リソース <a class="header-anchor" href="#_01-6-関連リソース" aria-label="Permalink to “01.6- 関連リソース”">​</a></h2><ul><li><a href="https://docs.github.com" target="_blank" rel="noreferrer">GitHub 公式ドキュメント</a></li><li><a href="/ja/91git.html">Git 基礎チュートリアル</a></li><li><a href="/ja/全部资源概述.html">全リソース概要</a></li></ul>`,38)]))}const b=i(l,[["render",t]]);export{c as __pageData,b as default};
